// modules/admin/workflows/workflow.models.ts

// Grid item — flat, for list display
export interface WorkflowGridItemDTO {
  id: string;
  name: string;
  slug: string;
  provisioningMode: EnumDTO;
  stepCount: number;
  createdDate: string;
}

// Full DTO — complete entity shape (GET response)
export interface WorkflowDTO {
  id: string;
  name: string;
  slug: string;
  provisioningMode: EnumDTO;
  defaultRole: EnumDTO;
  domainAllowlist: string[] | null;
  requireReauthOnTenantSwitch: boolean;
  steps: WorkflowStepDTO[];
  stepCount: number;
  createdDate: string;
  updatedDate: string | null;
}

// Child DTO
export interface WorkflowStepDTO {
  id: string;
  userId: string;
  displayName: string;
  email: string;
  platformRole: EnumDTO;
  status: EnumDTO;
  joinedAt: string;
}

// Save request — same shape as DTO (roundtrip pattern)
export interface SaveWorkflowRequest {
  id: string;
  name: string;
  slug: string;
  provisioningMode: EnumDTO;
  defaultRole: EnumDTO;
  domainAllowlist: string[] | null;
  requireReauthOnTenantSwitch: boolean;
  steps: WorkflowStepDTO[];
}

// Save response
export interface SaveWorkflowResponse {
  id: string;
}

// Shared types (from @nxgn-solutions/ui or shared models)
export interface EnumDTO {
  id: number;
  name: string;
}

export interface NamedDTO {
  id: string;
  name: string;
  description?: string;
}

