import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';
import { GridListResponse } from '@nxgn-solutions/ui';
import {
  WorkflowDTO,
  WorkflowGridItemDTO,
  SaveWorkflowRequest,
  SaveWorkflowResponse,
} from './workflow.models';

@Injectable({ providedIn: 'root' })
export class WorkflowService {
  private readonly http = inject(HttpClient);
  private readonly baseUrl = '/api/v1/workflows';

  // Read operations
  getGridList(page: number, pageSize: number, search?: string): Promise<GridListResponse<WorkflowGridItemDTO>> {
    return firstValueFrom(
      this.http.post<GridListResponse<WorkflowGridItemDTO>>(
        `${this.baseUrl}/grid-list`,
        { page, pageSize, search }
      )
    );
  }

  get(id: string): Promise<WorkflowDTO> {
    return firstValueFrom(this.http.get<WorkflowDTO>(`${this.baseUrl}/${id}`));
  }

  // Write operations
  save(request: SaveWorkflowRequest): Promise<SaveWorkflowResponse> {
    return firstValueFrom(
      this.http.post<SaveWorkflowResponse>(this.baseUrl, request)
    );
  }

  delete(entityKeys: string[]): Promise<void> {
    return firstValueFrom(
      this.http.post<void>(`${this.baseUrl}/delete`, { entityKeys })
    );
  }

  // Lookups
  getLookupList(): Promise<NamedDTO[]> {
    return firstValueFrom(this.http.get<NamedDTO[]>(`${this.baseUrl}/lookup`));
  }

  // Domain commands (if applicable)
  setProvisioningMode(id: string, mode: EnumDTO): Promise<void> {
    return firstValueFrom(
      this.http.put<void>(`${this.baseUrl}/${id}/provisioning`, { provisioningMode: mode })
    );
  }
}

