import { Component, inject, signal, OnInit, ChangeDetectionStrategy } from '@angular/core';
import { Router } from '@angular/router';
import { ColDef } from 'ag-grid-community';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { ToastrService } from 'ngx-toastr';
import { GridPageTitleComponent, DataGridComponent, ConfirmationDialogService } from '@nxgn-solutions/ui';
import { WorkflowService } from './workflow.service';
import { WorkflowGridItemDTO } from './workflow.models';

@Component({
  selector: 'app-workflow-list',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [GridPageTitleComponent, DataGridComponent, TranslatePipe],
  templateUrl: './workflow-list.component.html',
})
export class WorkflowListComponent implements OnInit {
  private readonly workflowService = inject(WorkflowService);
  private readonly router = inject(Router);
  private readonly toastr = inject(ToastrService);
  private readonly confirmService = inject(ConfirmationDialogService);
  private readonly translate = inject(TranslateService);

  // State signals
  readonly dataItems = signal<WorkflowGridItemDTO[]>([]);
  readonly loading = signal(true);
  readonly totalCount = signal(0);
  readonly selectedItems = signal<{ id: string }[]>([]);

  // Grid column definitions
  readonly columnDefs: ColDef<WorkflowGridItemDTO>[] = [
    { field: 'name', headerName: this.t('workflows.name') },
    { field: 'slug', headerName: this.t('workflows.slug') },
    {
      field: 'provisioningMode',
      headerName: this.t('workflows.provisioning_mode'),
      valueFormatter: (params) => params.value?.name ?? '',
    },
    { field: 'stepCount', headerName: this.t('workflows.step_count') },
    { field: 'createdDate', headerName: this.t('common.created_date') },
  ];

  ngOnInit(): void {
    this.loadGrid();
  }

  // Grid events
  onSelectionChanged(rows: WorkflowGridItemDTO[]): void {
    this.selectedItems.set(rows.map(r => ({ id: r.id })));
  }

  onRowDoubleClicked(row: WorkflowGridItemDTO): void {
    this.router.navigate(['/admin/workflows', row.id]);
  }

  // Toolbar actions
  onAdd(): void {
    this.router.navigate(['/admin/workflows/new']);
  }

  onEdit(): void {
    const selected = this.selectedItems();
    if (selected.length === 1) {
      this.router.navigate(['/admin/workflows', selected[0].id]);
    }
  }

  async onDelete(): Promise<void> {
    const selected = this.selectedItems();
    if (selected.length === 0) return;

    const confirmed = await this.confirmService.confirmDelete(
      this.t('workflows.delete_title'),
      this.t('workflows.delete_message', { count: selected.length })
    );
    if (!confirmed) return;

    try {
      await this.workflowService.delete(selected.map(s => s.id));
      this.toastr.success(this.t('workflows.deleted'));
      await this.loadGrid();
    } catch {
      this.toastr.error(this.t('common.delete_error'));
    }
  }

  // Data loading
  private async loadGrid(): Promise<void> {
    this.loading.set(true);
    try {
      const response = await this.workflowService.getGridList(1, 100);
      this.dataItems.set(response.items);
      this.totalCount.set(response.totalCount);
    } finally {
      this.loading.set(false);
    }
  }

  private t(key: string, params?: Record<string, unknown>): string {
    return this.translate.instant(key, params);
  }
}

