import {
  Component, inject, input, signal, computed, effect,
  ChangeDetectionStrategy,
} from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { ToastrService } from 'ngx-toastr';
import {
  CapturePageTitleComponent, TextFieldComponent, DropdownFieldComponent,
  CheckboxFieldComponent, TextAreaFieldComponent,
} from '@nxgn-solutions/ui';
import { WorkflowService } from './workflow.service';
import { WorkflowDTO, SaveWorkflowRequest, EnumDTO } from './workflow.models';

const EMPTY_GUID = '00000000-0000-0000-0000-000000000000';
const GUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

@Component({
  selector: 'app-workflow-capture',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CapturePageTitleComponent, TextFieldComponent, DropdownFieldComponent,
    CheckboxFieldComponent, TextAreaFieldComponent, TranslatePipe,
  ],
  templateUrl: './workflow-capture.component.html',
})
export class WorkflowCaptureComponent {
  private readonly workflowService = inject(WorkflowService);
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly toastr = inject(ToastrService);
  private readonly translate = inject(TranslateService);

  // Route param (bound via withComponentInputBinding)
  readonly id = input<string>();

  // Mode detection
  readonly isEditMode = computed(() => GUID_REGEX.test(this.id() ?? ''));

  // Form field signals
  readonly name = signal('');
  readonly slug = signal('');
  readonly selectedProvisioningMode = signal<EnumDTO | null>(null);
  readonly selectedDefaultRole = signal<EnumDTO | null>(null);
  readonly domainAllowlist = signal('');
  readonly requireReauthOnTenantSwitch = signal(false);

  // Lookup data
  readonly provisioningModeOptions: EnumDTO[] = [
    { id: 0, name: 'Auto' },
    { id: 1, name: 'Manual' },
    { id: 2, name: 'Approval' },
  ];

  // UI state
  readonly loading = signal(false);
  readonly saving = signal(false);
  readonly errorMessage = signal('');
  private slugManuallyEdited = false;

  // Validation — per-field computed error arrays
  readonly nameErrors = computed(() => {
    const errors: string[] = [];
    const n = this.name().trim();
    if (!n) errors.push(this.t('validation.required'));
    if (n.length > 255) errors.push(this.t('validation.max_length', { max: 255 }));
    return errors;
  });

  readonly slugErrors = computed(() => {
    const errors: string[] = [];
    const s = this.slug().trim();
    if (!s) errors.push(this.t('validation.required'));
    if (s.length > 100) errors.push(this.t('validation.max_length', { max: 100 }));
    if (s && !/^[a-z0-9-]+$/.test(s)) errors.push(this.t('validation.slug_format'));
    return errors;
  });

  // Master form validity — gates Save button
  readonly isFormValid = computed(() => {
    if (this.saving() || this.loading()) return false;
    if (this.nameErrors().length > 0) return false;
    if (this.slugErrors().length > 0) return false;
    if (!this.selectedProvisioningMode()) return false;
    if (!this.selectedDefaultRole()) return false;
    return true;
  });

  constructor() {
    // Effect: load entity when route param changes (edit mode)
    effect(() => {
      const id = this.id();
      if (id && GUID_REGEX.test(id)) {
        this.loadEntity(id);
      }
    });

    // Effect: auto-generate slug from name (create mode only)
    effect(() => {
      const n = this.name();
      if (!this.isEditMode() && !this.slugManuallyEdited) {
        this.slug.set(n.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''));
      }
    });
  }

  // Slug manual edit tracking
  onSlugInput(): void {
    this.slugManuallyEdited = true;
  }

  // Save handler
  async onSave(): Promise<void> {
    if (!this.isFormValid()) return;

    this.saving.set(true);
    this.errorMessage.set('');

    try {
      const request: SaveWorkflowRequest = {
        id: this.isEditMode() ? this.id()! : EMPTY_GUID,
        name: this.name().trim(),
        slug: this.slug().trim(),
        provisioningMode: this.selectedProvisioningMode()!,
        defaultRole: this.selectedDefaultRole()!,
        domainAllowlist: this.domainAllowlist()
          ? this.domainAllowlist().split('\n').map(d => d.trim()).filter(Boolean)
          : null,
        requireReauthOnTenantSwitch: this.requireReauthOnTenantSwitch(),
        steps: [],  // simplified — see capture state for full step management
      };

      const response = await this.workflowService.save(request);

      if (!this.isEditMode()) {
        this.toastr.success(this.t('workflows.created'));
        this.router.navigate(['/admin/workflows', response.id]);
      } else {
        this.toastr.success(this.t('workflows.updated'));
        await this.loadEntity(this.id()!);
      }
    } catch (err: any) {
      this.errorMessage.set(err?.error?.message ?? this.t('common.save_error'));
    } finally {
      this.saving.set(false);
    }
  }

  onCancel(): void {
    this.router.navigate(['/admin/workflows']);
  }

  // Data loading
  private async loadEntity(id: string): Promise<void> {
    this.loading.set(true);
    try {
      const dto = await this.workflowService.get(id);
      this.name.set(dto.name);
      this.slug.set(dto.slug);
      this.selectedProvisioningMode.set(dto.provisioningMode);
      this.selectedDefaultRole.set(dto.defaultRole);
      this.domainAllowlist.set(dto.domainAllowlist?.join('\n') ?? '');
      this.requireReauthOnTenantSwitch.set(dto.requireReauthOnTenantSwitch);
    } catch {
      this.errorMessage.set(this.t('common.load_error'));
    } finally {
      this.loading.set(false);
    }
  }

  private t(key: string, params?: Record<string, unknown>): string {
    return this.translate.instant(key, params);
  }
}

