import { Injectable, signal } from '@angular/core';
import { ActionEvidenceDTO, ActionConsultationDTO } from './action.models';

@Injectable()  // NO providedIn — component-scoped, fresh per mount
export class ActionCaptureState {
  readonly actionId = signal<string>('');
  readonly evidence = signal<ActionEvidenceDTO[]>([]);
  readonly consultations = signal<ActionConsultationDTO[]>([]);
}

@Component({
  // ...
  providers: [ActionCaptureState],  // scoped to this component instance
})
export class ActionCaptureComponent {
  private readonly state = inject(ActionCaptureState);

  // Alias for template convenience
  readonly evidence = this.state.evidence;

  // Track server-assigned IDs for new/existing detection on save
  private serverEvidenceIds = new Set<string>();

  private async loadEntity(id: string): Promise<void> {
    const dto = await this.actionService.get(id);
    // Populate state for child routes
    this.state.actionId.set(dto.id);
    this.state.evidence.set(dto.evidence);
    this.state.consultations.set(dto.consultations);
    this.serverEvidenceIds = new Set(dto.evidence.map(c => c.id));
  }

  async onSave(): Promise<void> {
    const request = {
      // ...
      evidence: this.state.evidence().map(c => ({
        ...c,
        id: this.serverEvidenceIds.has(c.id) ? c.id : EMPTY_GUID,  // new items → EMPTY_GUID
      })),
    };
    // save...
  }
}

